/*
 * Queue Data Structure Implementation in C
 * Demonstrates FIFO principle with array-based implementation
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX 5

// Global queue array and pointers
int queue[MAX];
int front = -1;
int rear = -1;

// Function prototypes
bool isEmpty();
bool isFull();
void enqueue(int value);
int dequeue();
int peek();
void display();

// Check if queue is empty
bool isEmpty() {
 return (front == -1 || front > rear);
}

// Check if queue is full
bool isFull() {
 return (rear == MAX - 1);
}

// Add element to rear of queue
void enqueue(int value) {
 if (isFull()) {
 printf("Queue Overflow! Cannot enqueue %d\n", value);
 } else {
 if (front == -1) {
 front = 0;
 }
 rear++;
 queue[rear] = value;
 printf("%d enqueued to queue\n", value);
 }
}

// Remove and return element from front
int dequeue() {
 if (isEmpty()) {
 printf("Queue Underflow! Cannot dequeue\n");
 return -1;
 } else {
 int value = queue[front];
 front++;

 // Reset queue when all elements removed
 if (front > rear) {
 front = rear = -1;
 }

 printf("%d dequeued from queue\n", value);
 return value;
 }
}

// View front element without removing
int peek() {
 if (isEmpty()) {
 printf("Queue is Empty\n");
 return -1;
 } else {
 return queue[front];
 }
}

// Display queue contents
void display() {
 if (isEmpty()) {
 printf("Queue: [ ] (Empty)\n");
 } else {
 printf("Queue: [");
 for (int i = front; i <= rear; i++) {
 printf("%d", queue[i]);
 if (i < rear) printf(", ");
 }
 printf("]\n");
 printf("Front index: %d, Rear index: %d\n", front, rear);
 }
}

// Main function demonstrating queue operations
int main() {
 printf("=== Queue Operations in C ===\n\n");

 // Enqueue operations
 printf("--- Enqueue Operations ---\n");
 enqueue(10);
 enqueue(20);
 enqueue(30);
 display();

 // Peek operation
 printf("\n--- Peek Operation ---\n");
 printf("Front element: %d\n", peek());
 display();

 // Dequeue operations - FIFO order
 printf("\n--- Dequeue Operations ---\n");
 dequeue(); // Returns 10 (first in)
 display();
 dequeue(); // Returns 20 (second in)
 display();

 // Demonstrate memory wastage problem
 printf("\n--- Demonstrating Memory Wastage ---\n");
 enqueue(40);
 enqueue(50);
 enqueue(60); // This will fail - queue appears full!
 display();
 printf("Note: Queue reports FULL but indices 0,1 are empty!\n");

 // Empty and show underflow
 printf("\n--- Demonstrating Underflow ---\n");
 dequeue(); // Returns 30
 dequeue(); // Returns 40
 dequeue(); // Returns 50
 dequeue(); // Returns 60
 dequeue(); // Underflow!

 return 0;
}

/*
 * Queue Data Structure Implementation in Java
 * Demonstrates FIFO principle with comprehensive error handling
 */

public class Queue {
 private int[] queue;
 private int front;
 private int rear;
 private int maxSize;
 private int currentSize;

 // Constructor with size
 public Queue(int size) {
 this.maxSize = size;
 this.queue = new int[maxSize];
 this.front = -1;
 this.rear = -1;
 this.currentSize = 0;
 }

 // Check if queue is empty
 public boolean isEmpty() {
 return front == -1 || front > rear;
 }

 // Check if queue is full
 public boolean isFull() {
 return rear == maxSize - 1;
 }

 // Get current size
 public int size() {
 return currentSize;
 }

 // Enqueue - Add element to rear
 public void enqueue(int value) throws QueueOverflowException {
 if (isFull()) {
 throw new QueueOverflowException("Queue Overflow! Cannot enqueue " + value);
 }

 if (front == -1) {
 front = 0;
 }
 rear++;
 queue[rear] = value;
 currentSize++;
 System.out.println(value + " enqueued to queue");
 }

 // Dequeue - Remove element from front
 public int dequeue() throws QueueUnderflowException {
 if (isEmpty()) {
 throw new QueueUnderflowException("Queue Underflow! Cannot dequeue");
 }

 int value = queue[front];
 front++;
 currentSize--;

 // Reset queue when empty
 if (front > rear) {
 front = rear = -1;
 }

 System.out.println(value + " dequeued from queue");
 return value;
 }

 // Peek - View front element
 public int peek() throws QueueUnderflowException {
 if (isEmpty()) {
 throw new QueueUnderflowException("Queue is Empty");
 }
 return queue[front];
 }

 // Display queue contents
 public void display() {
 if (isEmpty()) {
 System.out.println("Queue: [ ] (Empty)");
 } else {
 System.out.print("Queue: [ ");
 for (int i = front; i <= rear; i++) {
 System.out.print(queue[i]);
 if (i < rear) System.out.print(", ");
 }
 System.out.println(" ]");
 System.out.println("Front: " + front + ", Rear: " + rear + ", Size: " + currentSize);
 }
 }

 // Custom Exception for Overflow
 static class QueueOverflowException extends Exception {
 public QueueOverflowException(String message) {
 super(message);
 }
 }

 // Custom Exception for Underflow
 static class QueueUnderflowException extends Exception {
 public QueueUnderflowException(String message) {
 super(message);
 }
 }

 // Main demonstration
 public static void main(String[] args) {
 Queue q = new Queue(5);

 System.out.println("=== Queue Operations in Java ===\n");

 // Enqueue operations
 System.out.println("--- Enqueue Operations ---");
 try {
 q.enqueue(10);
 q.enqueue(20);
 q.enqueue(30);
 q.display();

 // Peek operation
 System.out.println("\n--- Peek Operation ---");
 System.out.println("Front element: " + q.peek());
 q.display();

 // Dequeue operations (FIFO)
 System.out.println("\n--- Dequeue Operations ---");
 q.dequeue(); // Returns 10
 q.display();
 q.dequeue(); // Returns 20
 q.display();

 // Add more and demonstrate overflow
 System.out.println("\n--- Adding More Elements ---");
 q.enqueue(40);
 q.enqueue(50);
 q.enqueue(60); // May cause overflow
 q.display();

 } catch (QueueOverflowException e) {
 System.out.println("Exception: " + e.getMessage());
 } catch (QueueUnderflowException e) {
 System.out.println("Exception: " + e.getMessage());
 }
 }
}
